**Save a memory:**
```js
async function remember(userId, type, content, key = null, metadata = null) {
  return db.agentMemory.upsert({
    where: { userId_agentId_key: { userId, agentId: 'research-agent', key: key || content.slice(0,50) } },
    update: { content, metadata, updatedAt: new Date() },
    create: { userId, agentId: 'research-agent', type, key, content, metadata }
  });
}
```

**Retrieve memories:**
```js
async function recall(userId, type, limit = 10) {
  return db.agentMemory.findMany({
    where: { userId, type, OR: [{ expiresAt: null }, { expiresAt: { gt: new Date() } }] },
    orderBy: { updatedAt: 'desc' },
    take: limit
  });
}
```

**Inject into system prompt:**
```js
const memories = await recall(userId, 'preference');
const findings = await recall(userId, 'finding', 5);
const systemPrompt = `
User preferences:\n${memories.map(m => m.content).join('\n')}

Recent findings:\n${findings.map(m => m.content).join('\n')}
${originalSystemPrompt}`;
```

After each agent run, extract and save the key memories:

```js
async function extractMemories(userId, sessionMessages) {
  // Ask Claude to extract key memories from the session
  const extraction = await client.messages.create({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 500,
    messages: [{
      role: 'user',
      content: `From this conversation, extract:
1. Any user preferences mentioned (format: PREFERENCE: [text])
2. Any factual findings made (format: FINDING: [text])
3. Any decisions made and why (format: DECISION: [text])
4. Any errors encountered (format: ERROR: [text])

Conversation:
${sessionMessages.map(m => `${m.role}: ${JSON.stringify(m.content)}`).join('\n')}`
    }]
  });

  // Parse and save each memory
  const text = extraction.content[0].text;
  const preferences = text.match(/PREFERENCE: (.+)/g) || [];
  const findings = text.match(/FINDING: (.+)/g) || [];
  // ... save each to DB
}
```

This uses Claude to do the hard work of deciding what's worth remembering — then saves only the signal, not the noise.

**Step 1: Generate an embedding**
```js
import OpenAI from 'openai'; // Use OpenAI's embedding model (1536 dimensions)
const openai = new OpenAI();
async function embed(text) {
  const response = await openai.embeddings.create({
    model: 'text-embedding-3-small',
    input: text
  });
  return response.data[0].embedding; // Array of 1536 floats
}
```

**Step 2: Store with pgvector**
```sql
-- Enable pgvector extension
CREATE EXTENSION IF NOT EXISTS vector;
-- Add vector column to your memory table
ALTER TABLE agent_memory ADD COLUMN embedding vector(1536);
```

**Step 3: Semantic search query**
```js
async function semanticSearch(query, userId, limit = 5) {
  const queryVector = await embed(query);
  const results = await db.$queryRaw`
    SELECT id, content, type,
           1 - (embedding <=> ${queryVector}::vector) AS similarity
    FROM agent_memory
    WHERE user_id = ${userId}
    ORDER BY embedding <=> ${queryVector}::vector
    LIMIT ${limit}
  `;
  return results;
}
```

`<=>` is the cosine distance operator in pgvector. Results closest to 0 distance = most similar.

**RAG (Retrieval-Augmented Generation)** = semantic search → inject results → Claude generates grounded response.

Pattern:
```js
async function ragResponse(userQuery, userId) {
  // 1. Find relevant memories
  const relevantMemories = await semanticSearch(userQuery, userId, 5);

  // 2. Build context from memories
  const context = relevantMemories
    .filter(m => m.similarity > 0.7) // Only high-confidence matches
    .map(m => m.content)
    .join('\n---\n');

  // 3. Generate response grounded in memories
  const response = await client.messages.create({
    model: 'claude-opus-4-6',
    messages: [{ role: 'user', content: userQuery }],
    system: `Use this context to answer the user's question. Only use information from the context.
Context:\n${context}
If the context doesn't contain the answer, say so.`
  });
  return response.content[0].text;
}
```

The key: `filter(m => m.similarity > 0.7)` — only inject highly relevant memories. Low-similarity 'matches' add noise, not signal.

**Phase 1: Ingestion (run once + on updates)**
```js
async function ingestDocument(doc) {
  // 1. Chunk the document (1000-char chunks with 200-char overlap)
  const chunks = chunkText(doc.content, 1000, 200);
  // 2. Embed each chunk
  for (const chunk of chunks) {
    const embedding = await embed(chunk);
    await db.documentChunk.create({
      data: { docId: doc.id, content: chunk, embedding, metadata: doc.metadata }
    });
  }
}
```

**Why chunks with overlap?** A 10,000-word document is too big for one embedding (loses specificity). Chunks of ~1000 chars each have focused meaning. Overlap (200 chars shared between chunks) prevents answers from straddling chunk boundaries.

**Phase 2: Query (real-time)**
```js
async function ragAnswer(question, topK = 5) {
  // 1. Embed the question
  const queryEmbedding = await embed(question);
  // 2. Find top-K most similar chunks
  const chunks = await vectorSearch(queryEmbedding, topK);
  // 3. Format context with source citations
  const context = chunks.map((c, i) => `[Source ${i+1}: ${c.metadata.title}]\n${c.content}`).join('\n\n');
  // 4. Generate grounded answer
  return client.messages.create({ system: `Answer using only the provided sources. Cite sources as [Source N].\n\nSources:\n${context}`, messages: [{ role: 'user', content: question }] });
}
```

Two metrics define RAG quality:

**1. Retrieval Relevance**
Are the retrieved chunks actually relevant to the question?
- Check: for 10 test questions, are the top 3 retrieved chunks on-topic?
- Fix if poor: adjust chunk size, improve embedding model, add metadata filtering

**2. Faithfulness**  
Does the generated answer stick to the retrieved content?
- Check: find claims in the answer, verify each claim appears in the retrieved chunks
- Fix if poor: stronger system prompt instruction ('ONLY use information from the provided context'), use a lower-temperature model

**Automated evaluation:**
```js
async function evaluateFaithfulness(question, context, answer) {
  const eval = await client.messages.create({
    messages: [{ role: 'user', content:
      `Does this answer contain ONLY information from the context? Answer FAITHFUL or HALLUCINATED + explain.

Context: ${context}
Answer: ${answer}` }]
  });
  return eval.content[0].text;
}
```

Run this on 20 sample questions to benchmark your RAG system before deploying.
